DOMAIN: schema-grammar
INPUT:
interface Profile {
  max_retries: number;
  retryCount?: number;
  node_id: boolean;
  port: string;
}
OUTPUT:
Profile
  = max_retries:MaxRetriesSection EOL node_id:NodeIdSection EOL port:PortSection retryCount:RetryCountOpt EOLopt
    { return { max_retries: max_retries, node_id: node_id, port: port, retryCount: retryCount }; }

MaxRetriesSection
  = "MAX_RETRIES:" _ v:Integer { return v; }

NodeIdSection
  = "NODE_ID:" _ v:Bool { return v; }

PortSection
  = "PORT:" _ v:QuotedString { return v; }

RetryCountOpt
  = EOL "RETRY_COUNT:" _ v:Float { return v; }
  / "" { return undefined; }

Bool = "yes" { return true; } / "no" { return false; }
QuotedString = '"' chars:$[^"]* '"' { return chars; }
Float = chars:$([0-9]+ ("." [0-9]+)?) { return parseFloat(chars); }
Integer = chars:$[0-9]+ { return parseInt(chars, 10); }
_ = [ \t]*
EOL = _ "\n"
EOLopt = (_ "\n")?

